"use strict";(globalThis.webpackChunkmy_blog=globalThis.webpackChunkmy_blog||[]).push([[8130],{7735(n){n.exports=JSON.parse("{\"archive\":{\"blogPosts\":[{\"id\":\"ai-collaboration-and-technical-depth\",\"metadata\":{\"permalink\":\"/blog/ai-collaboration-and-technical-depth\",\"editUrl\":\"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/ai-collaboration-and-technical-depth.md\",\"source\":\"@site/blog/ai-collaboration-and-technical-depth.md\",\"title\":\"\u5584\u7528\u5de5\u5177\u5f25\u8865\u6280\u672f\u6df1\u5ea6\",\"description\":\"\u8fd9\u662f\u4e00\u7bc7\u5173\u4e8e\u5c0f\u767d\u5728\u6ca1\u6709\u4efb\u4f55\u6280\u672f\u6df1\u5ea6\uff0c\u4f46\u662f\u5728\u5584\u4e8e\u4f7f\u7528AI\u5de5\u5177\u7684\u60c5\u51b5\u4e0b\uff0c\u80fd\u5426\u5f25\u8865\u6280\u672f\u6df1\u5ea6\u9e3f\u6c9f\u7684\u63a2\u8ba8\u3002\",\"date\":\"2026-03-13T00:00:00.000Z\",\"tags\":[],\"readingTime\":8.44,\"hasTruncateMarker\":true,\"authors\":[],\"frontMatter\":{\"slug\":\"ai-collaboration-and-technical-depth\",\"title\":\"\u5584\u7528\u5de5\u5177\u5f25\u8865\u6280\u672f\u6df1\u5ea6\",\"date\":\"2026-03-13T00:00:00.000Z\"},\"unlisted\":false,\"nextItem\":{\"title\":\"\u963f\u91cc\u5929\u6c60\u4e8c\u624b\u8f66\u4ef7\u683c\u9884\u6d4b\u6bd4\u8d5bTop2\u5206\u4eab\",\"permalink\":\"/blog/mdx-blog-post\"}},\"content\":\"\u8fd9\u662f\u4e00\u7bc7\u5173\u4e8e\u5c0f\u767d\u5728\u6ca1\u6709\u4efb\u4f55\u6280\u672f\u6df1\u5ea6\uff0c\u4f46\u662f\u5728\u5584\u4e8e\u4f7f\u7528AI\u5de5\u5177\u7684\u60c5\u51b5\u4e0b\uff0c\u80fd\u5426\u5f25\u8865\u6280\u672f\u6df1\u5ea6\u9e3f\u6c9f\u7684\u63a2\u8ba8\u3002\\n\\n## \u524d\u8a00\\n\\n\x3c!-- truncate --\x3e\\n\\n\u6211\u5728\u8ff7\u832b\u7684\u65f6\u5019\uff0c\u603b\u4f1a\u53bb\u7ffb\u4e00\u4e9b\u5927\u4f6c\u7684\u6587\u7ae0\u5bfb\u627e\u65b9\u5411\uff0c\u6211\u7279\u522b\u60f3\u77e5\u9053\u5728AI\u6d2a\u6d41\u4e2d\uff0c\u600e\u4e48\u53bb\u63d0\u5347\u81ea\u5df1\uff0c\u4e8e\u662f\u6211\u7279\u5730\u53bb\u7ffb\u4e86\u4e00\u4e0b\u542f\u8499\u8001\u5e08\u7684\u535a\u5ba2\uff0c\u4e5f\u8bb8\u91cc\u9762\u5c31\u6709\u6211\u60f3\u8981\u7684\u7b54\u6848\u3002\u5728\u8fd9\u63d0\u4e00\u4e0b\uff0c\u7279\u522b\u611f\u8c22\u6211\u7684\u5bfc\u5e08\uff0c\u5e26\u6211\u8fdb\u5165\u5230AI\u884c\u4e1a\u4e2d\u3002\\n\\n\u611f\u5174\u8da3\u7684\u53ef\u4ee5\u70b9\u51fb\u67e5\u770b\u539f\u6587\uff1a\\n[AI\u6c34\u5e73\u4f9d\u7136\u4e0e\u7528\u6237\u6302\u94a9](https://jiangmiemie.com/blog/2026/2/28/)\\n\\n\u6587\u4e2d\u505a\u4e86\u4e00\u4e2a\u7279\u522b\u6709\u610f\u601d\u7684\u5b9e\u9a8c\uff1a\\n\\n\u4f7f\u7528`Opus 4.6`\u5728`Docusaurus`\u4e2d\u6dfb\u52a0\u201c\u590d\u5236 Markdown\u201d\u6309\u94ae\u7684\u5b9e\u9a8c\uff0c\u901a\u8fc7\u6a21\u62df\u5c0f\u767d\u3001\u57fa\u7840\u548c\u4e13\u5bb6\u4e09\u7c7b\u7528\u6237\uff0c\u63a2\u8ba8\u6280\u672f\u6df1\u5ea6\u5bf9AI\u534f\u4f5c\u6548\u7387\u7684\u5f71\u54cd\u3002\\n\\n\u6587\u7ae0\u91cc\u9762\u63d0\u5230\uff1a \\n**\u6280\u672f\u6df1\u5ea6\u53ef\u4ee5\u653e\u5927\u6a21\u578b\u7684\u80fd\u529b**\uff0c\u6211\u975e\u5e38\u8d5e\u540c\u3002\\n\\n\u4e0d\u77e5\u9053\u4f60\u4eec\u4f1a\u4e0d\u4f1a\u6709\u8fd9\u79cd\u611f\u89c9\uff0c\u5728\u4f7f\u7528AI\u7684\u65f6\u5019\u4f1a\u89c9\u5f97\u7279\u522b\u6ca1\u6709\u5b89\u5168\u611f\uff0c\u603b\u611f\u89c9\u7ed9\u6211\u57cb\u4e86\u4ec0\u4e48\u96f7\uff0c\u5373\u4f7f\u5b83\u662f\u4e16\u754c\u4e0a\u6700\u5f3a\u7684`claude`\\n\\n\u5f53\u81ea\u5df1\u60f3\u8ba4\u771f\u770b\u4e00\u4e0bai\u6539\u4e86\u4ec0\u4e48\u7684\u65f6\u5019\uff0c\u65f6\u5e38\u56e0\u4e3a\u81ea\u5df1\u6280\u672f\u4e0d\u591f\u6df1\u5165\uff0c\u53d1\u73b0review\u8d77\u6765\u975e\u5e38\u5403\u529b\uff0c\u6709\u65f6\u5019\u76f4\u63a5\u4e0d\u60f3\u770b\u4e86\u3002\\n\\n\u5e76\u4e14\u7531\u4e8e\u6280\u672f\u6c34\u5e73\u7684\u4e0a\u9650\uff0c\u6839\u672c\u65e0\u6cd5\u5224\u65adAI\u5199\u7684\u662f\u5426\u6b63\u786e\uff0c\u5199\u7684\u4e0d\u597d\u8981\u4e48\u7ed9AI\u91cd\u65b0\u6539\uff0c\u641e\u4e71\u4e86\u53ea\u80fd\u4f5c\u4e3aAI\u5783\u573e\u4e22\u6389\uff0c\u91cd\u5934\u518d\u6765\u3002\\n\\n\u6587\u7ae0\u4e2d\u7684\u5c0f\u767d\u5728\u6700\u540e\u5e76\u6ca1\u6709\u5b8c\u6210\uff0c\u539f\u6587\u8bf4\u5230\uff1a<span style={{color: '#ff4444'}}>\u9057\u61be\u7684\u662f\uff0c\u4fee\u590d\u540e\u6837\u5f0f\u4f9d\u7136\u4e0d\u6b63\u786e\uff0c7\u6b21\u673a\u4f1a\u7528\u5b8c\u4e86\u3002</span>\\n\\n\u4f46\u662f\u6211\u8ba4\u4e3a\uff1a\\n\\n\u5927\u6a21\u578b\u53d1\u5c55\u5230\u4e86\u4eca\u5929\uff0c<span style={{color: '#ff6b35'}}>\u5584\u4e8e\u4f7f\u7528\u5de5\u5177\u5df2\u7ecf\u53ef\u4ee5\u505a\u5230\u5f25\u8865\u6280\u672f\u6df1\u5ea6\u7684\u4e0d\u8db3\u3002</span>\u8fd9\u6837\u7684\u5c0f\u9700\u6c42\uff0c\u4e0d\u5e94\u8be5\u57287\u6b21\u5bf9\u8bdd\u4e0b\u4f9d\u65e7\u65e0\u6cd5\u5b8c\u6210\u3002\\n\\n\u8bf4\u5b9e\u8bdd\uff0c\u867d\u7136\u6211\u7684\u535a\u5ba2\u662f\u7528`Docusaurus`\u6846\u67b6\u5199\u7684\uff0c\u4f46\u6211\u5176\u5b9e\u53ea\u662f\u5f53\u4f5cmd\u7b14\u8bb0\u672c\u4e00\u6837\u5199\uff0c\u6211\u5e76\u4e0d\u4e86\u89e3\u8fd9\u4e2a\u6846\u67b6\u5230\u5e95\u662f\u4e00\u4e2a\u4ec0\u4e48\u539f\u7406\uff0c\u4ec0\u4e48\u903b\u8f91\uff0c\u6211\u53ea\u77e5\u9053\u4e00\u4e9bmd\u6587\u6863\u7684\u683c\u5f0f\uff0c\u548c\u542f\u52a8\u547d\u4ee4\u662f`npm run start`\uff0c\u5176\u4ed6\u4ec0\u4e48\u7f8e\u5316\u6211\u90fd\u662f\u4ea4\u7ed9ai\u6253\u7406\u3002\\n\\n\u90a3\u5bf9\u4e8e\u6211\u8fd9\u4e2a\u5c0f\u767d\u6765\u8bf4\uff0c\u80fd\u5426\u5728\u4f7f\u7528\u4e00\u4e9b\u5de5\u5177\u6280\u5de7\u7684\u60c5\u51b5\u4e0b\u5b8c\u6210\u8fd9\u4e2a\u9700\u6c42\u5462\uff1f\\n\\n\u8bdd\u4e0d\u591a\u8bf4\uff0c\u5f00\u59cb\u5427\uff01\\n\\n## \u5de5\u5177\u9009\u62e9\\n\\n\u5bf9\u4e8e\u8fd9\u79cd\u9700\u6c42\u6765\u8bf4\uff0c`claude code`\u7b80\u76f4\u592a\u9002\u5408\u4e86\u4e86\u3002\u8fd9\u6b21\u6211\u53ea\u6253\u5f00\u7ec8\u7aef\uff0c\u4e0d\u6253\u5f00ide\uff0c\u5b8c\u5168\u7531\u5b83\u64cd\u4f5c\uff0c\u5168\u7a0b\u7528\u81ea\u7136\u8bed\u8a00\uff0c\u770b\u770b\u9700\u8981\u51e0\u8f6e\u6765\u5b8c\u6210\u3002\\n\\n## \u8fdb\u5165\u8ba1\u5212\u6a21\u5f0f\\n\\n\u9996\u5148\uff0c\u8fd9\u79cd\u9700\u8981\u53c2\u8003\u4e00\u4e2a\u9879\u76ee\u6765\u5b9e\u73b0\u7684\uff0c\u76f4\u63a5\u65e0\u8111\u8ba1\u5212\u6a21\u5f0f\u5c31\u884c\u4e86\uff0c\u8fdb\u5165\u8ba1\u5212\u6a21\u5f0f\uff0c\u8f93\u5165\u7b80\u6d01\u7684\u9700\u6c42\u540e\uff0c\u52a0\u4e0a\u4e00\u53e5\u7279\u522b\u7684\u63d0\u793a\u8bcd\\n\\n![1773412277325](image/ai-collaboration-and-technical-depth/1773412277325.png)\\n\\n\u8fd9\u4e2a\u63d0\u793a\u8bcd\u4e5f\u6ca1\u5565\u795e\u5947\uff0c\u5c31\u662f\u8ba9\u5927\u6a21\u578b\u8fdb\u884c\u63d0\u95ee\u6f84\u6e05\uff0c\u4f46\u662f\u786e\u5b9e\u7279\u522b\u6709\u7528\u3002\\n\\n\u5927\u6a21\u578b\u53d1\u5c55\u5230\u4eca\u5929\uff0c\u4eba\u7c7b\u4f20\u7edf\u601d\u7ef4\u7684\u7ea6\u675f\u4e5f\u8bb8\u4f1a\u9650\u5236\u6a21\u578b\u7684\u53d1\u6325\uff0c\u8fd9\u4e5f\u662f\u4e3a\u4ec0\u4e48`claude code`\u5de5\u7a0b\u5e08\u540e\u9762\u653e\u5f03\u4e86`RAG`\u68c0\u7d22\u4ee3\u7801\u5e93\u7684\u65b9\u5f0f\uff0c\u800c\u662f\u53ea\u7ed9\u5b83\u4e00\u4e2a`grep`\uff0c\u56e0\u4e3a\u4ed6\u4eec\u76f8\u4fe1\uff0c\u5927\u6a21\u578b\u66f4\u61c2\u81ea\u5df1\u9700\u8981\u4ec0\u4e48\u3002\\n\\n\u6309\u4e0b\u56de\u8f66\u952e\u540e\uff0c\u5b83\u5f00\u59cb\u63a2\u7d22\u94fe\u63a5\u7684\u9879\u76ee\u5185\u5bb9\uff0c\u5728\u4e00\u6bb5\u65f6\u95f4\u7684\u63a2\u7d22\u540e\uff0c\u5b83\u5f00\u59cb\u5411\u6211\u63d0\u95ee\uff1a\\n\\n![1773412730316](image/ai-collaboration-and-technical-depth/1773412730316.png)\\n\\n\u7d27\u63a5\u7740\u53c8\u95ee\u4e86\u6211\u7b2c\u4e8c\u4e2a\u95ee\u9898\uff1a\\n\\n![1773412765938](image/ai-collaboration-and-technical-depth/1773412765938.png)\\n\\n\u4e24\u4e2a\u95ee\u9898\u56de\u7b54\u540e\uff0c\u5b83\u5c31\u5f00\u59cb\u5199\u8ba1\u5212\u4e86\uff0c\u4e0b\u9762\u662f\u5b83\u5199\u7684\u8ba1\u5212\uff1a\\n\\n````markdown\\n# \u4e3a Docs \u9875\u9762\u6dfb\u52a0\u300c\u590d\u5236 Markdown\u300d\u6309\u94ae\\n\\n## Context\\n\\n\u7528\u6237\u5e0c\u671b\u53c2\u8003 [FlyNumber/markdown_docusaurus_plugin](https://github.com/FlyNumber/markdown_docusaurus_plugin) \u7684\u5b9e\u73b0\uff0c\u4e3a\u535a\u5ba2\u7684 docs \u9875\u9762\u6dfb\u52a0\u4e00\u4e2a\\\"\u590d\u5236 Markdown\\\"\u6309\u94ae\u3002\u70b9\u51fb\u540e\u5c06\u5f53\u524d\u9875\u9762\u7684 Markdown \u6e90\u7801\u590d\u5236\u5230\u526a\u8d34\u677f\u3002\\n\\n\u6838\u5fc3\u601d\u8def\uff1a\u6784\u5efa\u65f6\u751f\u6210\u6e05\u6d17\u540e\u7684 `.md` \u6587\u4ef6 \u2192 \u6309\u94ae\u70b9\u51fb\u65f6 fetch \u8be5\u6587\u4ef6 \u2192 \u590d\u5236\u5230\u526a\u8d34\u677f\u3002\\n\\n## \u9700\u8981\u65b0\u5efa/\u4fee\u6539\u7684\u6587\u4ef6\\n\\n| \u6587\u4ef6 | \u64cd\u4f5c |\\n| ---- | ---- |\\n| `plugins/copy-markdown-source/index.js` | \u65b0\u5efa - \u672c\u5730 Docusaurus \u63d2\u4ef6\uff0cpostBuild \u751f\u6210 .md \u6587\u4ef6 |\\n| `src/components/CopyMarkdownButton/index.js` | \u65b0\u5efa - \u590d\u5236\u6309\u94ae React \u7ec4\u4ef6 |\\n| `src/components/CopyMarkdownButton/styles.module.css` | \u65b0\u5efa - \u6309\u94ae\u6837\u5f0f |\\n| `src/theme/Root.js` | \u4fee\u6539 - \u6269\u5c55\u73b0\u6709\u7ec4\u4ef6\uff0c\u6ce8\u5165\u6309\u94ae\u5230 docs \u9875\u9762 |\\n| `docusaurus.config.js` | \u4fee\u6539 - \u6ce8\u518c\u672c\u5730\u63d2\u4ef6 |\\n\\n## \u5b9e\u73b0\u6b65\u9aa4\\n\\n### 1. \u521b\u5efa\u672c\u5730\u63d2\u4ef6 `plugins/copy-markdown-source/index.js`\\n\\n\u4f7f\u7528 Docusaurus `postBuild` \u751f\u547d\u5468\u671f\u94a9\u5b50\uff1a\\n\\n- \u4ece `props.plugins` \u4e2d\u627e\u5230 `plugin-content-docs`\uff0c\u63d0\u53d6\u6240\u6709 doc \u7684 `permalink` \u548c `source` \u8def\u5f84\\n- \u8bfb\u53d6\u6e90 `.md/.mdx` \u6587\u4ef6\uff0c\u6267\u884c\u6e05\u6d17\uff08\u53bb frontmatter\u3001\u53bb import\u3001\u53bb MDX \u7ec4\u4ef6\u6807\u7b7e\uff09\\n- \u5c06\u6e05\u6d17\u540e\u7684\u5185\u5bb9\u5199\u5165 `{outDir}{permalink}.md`\\n\\n\u6e05\u6d17\u89c4\u5219\uff1a\\n- \u79fb\u9664 YAML frontmatter\uff08`---...---`\uff09\\n- \u79fb\u9664 `import` \u8bed\u53e5\\n- \u79fb\u9664 MDX \u7ec4\u4ef6\uff1a`<DocCardList />`\u3001`<CsvTable ... />`\u3001`<Tabs>`\u3001`<TabItem>` \u53ca\u95ed\u5408\u6807\u7b7e\\n- \u5408\u5e76\u591a\u4f59\u7a7a\u884c\\n- \u4fdd\u7559\u6807\u51c6 HTML \u6807\u7b7e\uff08`<mark>`\u3001`<span>`\u3001`<details>` \u7b49\uff09\u548c\u56fe\u7247\u5f15\u7528\\n\\n\u6ce8\u610f\uff1a\u63d2\u4ef6\u4f7f\u7528 CJS\uff08`module.exports`\uff09\uff0c\u56e0\u4e3a Docusaurus \u672c\u5730\u63d2\u4ef6\u5728 Node.js \u7aef\u8fd0\u884c\uff0c\u9879\u76ee `package.json` \u65e0 `\\\"type\\\": \\\"module\\\"`\uff0cCJS \u517c\u5bb9\u3002\u9700\u8981 `fs` \u548c `path`\uff08Node \u5185\u7f6e\uff09\uff0c\u65e0\u9700\u989d\u5916\u4f9d\u8d56\u3002\\n\\n### 2. \u521b\u5efa\u6309\u94ae\u7ec4\u4ef6 `src/components/CopyMarkdownButton/`\\n\\n\u7b80\u5355\u7684\u5355\u6309\u94ae\u7ec4\u4ef6\uff1a\\n- \u4ece `window.location.pathname` \u6784\u9020 `.md` \u6587\u4ef6 URL\uff08\u53bb\u5c3e\u90e8\u659c\u6760\u540e\u52a0 `.md`\uff09\\n- `fetch` \u8be5\u6587\u4ef6\uff0c`navigator.clipboard.writeText` \u590d\u5236\\n- \u72b6\u6001\u5207\u6362\uff1a\u9ed8\u8ba4\u663e\u793a\u590d\u5236\u56fe\u6807\uff0c\u6210\u529f\u540e\u663e\u793a\\\"\u5df2\u590d\u5236\\\"2 \u79d2\\n\\n\u6837\u5f0f\uff1a\u4f7f\u7528 CSS Modules\uff0c\u914d\u5408 `--ifm-color-primary` \u7b49 Docusaurus CSS \u53d8\u91cf\uff0c\u652f\u6301\u4eae/\u6697\u6a21\u5f0f\u3002\\n\\n### 3. \u4fee\u6539 `src/theme/Root.js`\\n\\n\u5728\u73b0\u6709 `PasswordProtect` \u5305\u88f9\u57fa\u7840\u4e0a\uff0c\u589e\u52a0 `useEffect`\uff1a\\n- \u68c0\u67e5\u5f53\u524d\u8def\u5f84\u662f\u5426\u4ee5 `/docs/` \u5f00\u5934\\n- \u67e5\u627e `article .markdown h1`\uff08\u6216 `article header`\uff09\uff0c\u5728\u5176\u540e\u6ce8\u5165\u6309\u94ae\u5bb9\u5668\\n- \u7528 `createRoot` \u6e32\u67d3 `CopyMarkdownButton`\\n- \u4f7f\u7528 `MutationObserver` \u76d1\u542c DOM \u53d8\u5316\uff0c\u5904\u7406\u5ba2\u6237\u7aef\u8def\u7531\u5207\u6362\u65f6\u7684\u91cd\u65b0\u6ce8\u5165\\n- \u901a\u8fc7 `data-copy-md-btn` \u5c5e\u6027\u9632\u6b62\u91cd\u590d\u6ce8\u5165\\n\\n### 4. \u4fee\u6539 `docusaurus.config.js`\\n\\n\u5728 config \u5bf9\u8c61\u4e2d\u65b0\u589e `plugins` \u5b57\u6bb5\uff08\u4e0e `presets` \u540c\u7ea7\uff09\uff1a\\n\\n```js\\nplugins: [\\n  './plugins/copy-markdown-source',\\n],\\n```\\n\\n## \u9a8c\u8bc1\u65b9\u5f0f\\n\\n1. `npm run build` \u2014 \u68c0\u67e5 `build/docs/` \u4e0b\u662f\u5426\u751f\u6210\u4e86\u5bf9\u5e94\u7684 `.md` \u6587\u4ef6\uff0c\u5185\u5bb9\u5df2\u6e05\u6d17\\n2. `npm run serve` \u2014 \u6253\u5f00\u4efb\u610f docs \u9875\u9762\uff0c\u786e\u8ba4\u6309\u94ae\u51fa\u73b0\u5728\u6807\u9898\u533a\u57df\\n3. \u70b9\u51fb\u6309\u94ae \u2192 \u7c98\u8d34\u5230\u7f16\u8f91\u5668\uff0c\u786e\u8ba4\u590d\u5236\u7684\u662f\u6e05\u6d17\u540e\u7684 Markdown \u6e90\u7801\\n4. \u6d4b\u8bd5\u5ba2\u6237\u7aef\u5bfc\u822a\uff1a\u5728 docs \u9875\u9762\u95f4\u5207\u6362\uff0c\u786e\u8ba4\u6309\u94ae\u6b63\u786e\u51fa\u73b0/\u6d88\u5931\\n5. \u786e\u8ba4\u975e docs \u9875\u9762\uff08\u9996\u9875\u3001\u535a\u5ba2\uff09\u4e0d\u663e\u793a\u6309\u94ae\\n````\\n\\n\u5f53\u7136\u4e86\u4f5c\u4e3a\u5c0f\u767d\uff0c\u5047\u88c5\u81ea\u5df1\u770b\u5b8c\u4e86\u6574\u4e2a\u8ba1\u5212\uff0c\u7136\u540e\u6309\u4e0b\u56de\u8f66\uff0c\u8fd9\u91cc\u5982\u679c\u81ea\u5df1\u6709\u6280\u672f\u6df1\u5ea6\u7684\u8bdd\uff0c\u4e5f\u8bb8\u4f1a\u8ba8\u8bba\u8ba1\u5212\u7684\u4fee\u6539\u3002\\n\\n## \u5f00\u59cb\u6267\u884c\\n\\n\u5f88\u5feb\u5b83\u5c31\u6309\u7167\u5f00\u59cb\u6267\u884c\\n\\n![1773413014324](image/ai-collaboration-and-technical-depth/1773413014324.png)\\n\\n\u8fd9\u91cc\u7ec6\u5fc3\u89c2\u5bdf\u7684\u8bdd\u4f1a\u53d1\u73b0\uff0c`claude code`\u7528\u7684\u4e0d\u518d\u662f`todo list`\u4e86\uff0c\u800c\u662f`task`\\n\\n\u4e3a\u4ec0\u4e48\u6362\u6210`task`\u7684\u8bdd\u53ef\u4ee5\u67e5\u770b\u8fd9\u7bc7\u6587\u7ae0 [Lessons from Building Claude Code: Seeing like an Agent](https://x.com/trq212/status/2027463795355095314?s=20)\uff0c\u8fd9\u91cc\u4e0d\u52a0\u8d58\u8ff0\u3002\\n\\n\u8fd9\u91cc\u5b83\u53d1\u73b0\u4e86\u4e00\u4e9b\u5173\u952e\u4fe1\u606f\uff1a\\n\\n![1773413468223](image/ai-collaboration-and-technical-depth/1773413468223.png)\\n\\n## \u5f00\u59cb\u9a8c\u8bc1\\n\\n\u5728[claude code\u7684\u6700\u4f73\u5b9e\u8df5](https://code.claude.com/docs/zh-CN/best-practices)\u4e2d\u63d0\u5230\uff1a\u7ed9`Claude`\u4e00\u79cd\u9a8c\u8bc1\u5176\u5de5\u4f5c\u7684\u65b9\u5f0f\u3002\\n\\n\u8fd9\u91cc\u5b83\u5f00\u59cb\u4e86\u81ea\u5df1\u7684\u9a8c\u8bc1\uff0c\u4e0d\u8fc7\u6211\u53ef\u6ca1\u8981\u6c42\u5b83\u9a8c\u8bc1\uff0c\u8fd9\u662f\u5b83\u81ea\u5df1\u7684\u8ba1\u5212\\n\\n![1773413713968](image/ai-collaboration-and-technical-depth/1773413713968.png)\\n\\n\u5b83\u53d1\u73b0\u4e86\u4e00\u4e9b\u95ee\u9898\uff0c\u5e76\u5c1d\u8bd5\u8c03\u8bd5\u4fee\u590d\uff0c\u6700\u540e\u53d1\u73b0\u662f\u540d\u5b57\u4e0d\u5bf9\\n\\n![1773413747767](image/ai-collaboration-and-technical-depth/1773413747767.png)\\n\\n\u7136\u540e\u5c31\u662f\u4e00\u987f\u64cd\u4f5c\uff0c\u6211\u5c31\u5403\u7740\u9ea6\u5f53\u52b3\uff0c\u6309\u4e0b\u56de\u8f66\uff0c\u8fd9\u5c31\u662f\u6211\u7684\u5de5\u4f5c\u3002\\n\\n![1773413819686](image/ai-collaboration-and-technical-depth/1773413819686.png)\\n\\n![1773413833638](image/ai-collaboration-and-technical-depth/1773413833638.png)\\n\\n![1773413839910](image/ai-collaboration-and-technical-depth/1773413839910.png)\\n\\n\u8fd9\u91cc\u8bf4\u4e00\u4e0b\uff0c\u5176\u5b9e\u6211\u4e5f\u4e0d\u77e5\u9053\u5b83\u9047\u5230\u5565\u95ee\u9898\u4e86\uff0c\u56e0\u4e3a\u6211\u5bf9\u8fd9\u6846\u67b6\u4e0d\u719f\u6089\uff0c\u4f46\u5b83\u4e00\u76f4\u5728\u64cd\u4f5c\u8ba9\u6211\u611f\u89c9\u6709\u70b9\u614c\u4e86\uff0c\u6211\u5f00\u59cb\u6000\u7591\u5b83\u80fd\u4e0d\u80fd\u5b8c\u6210\u3002\\n\\n## \u521d\u6b65\u6210\u529f\\n\\n\u8fd9\u91cc\u8bf4\u6784\u5efa\u6210\u529f\u4e86\uff0c\u63a5\u4e0b\u6765\u5c31\u662f\u6211\u9a8c\u6536\u6210\u679c\u4e86\uff0c\u8bf4\u5b9e\u8bdd\u8fd9\u79cd\u611f\u89c9\u597d\u50cf\u6709\u70b9\u723d\uff1a\\n\\n![1773413941292](image/ai-collaboration-and-technical-depth/1773413941292.png)\\n\\n\u6ca1\u9519\u6211\u9047\u5230\u4e86\u540c\u6837\u7684\u9519\u8bef\uff0c\u6309\u94ae\u4e0d\u5bf9\uff0c\u7136\u540e\u70b9\u51fb\u590d\u5236\u7adf\u7136\u4e0d\u662fmd\uff0c\u5230\u8fd9\u91cc\u6211\u65e0\u5948\u7684\u7b11\u4e86\uff0c\u679c\u7136AI\u8fd8\u662f\u9700\u8981\u6280\u672f\u6df1\u5ea6\u624d\u80fd\u7528\u597d\u5417\u3002\\n\\n\u8fd9\u91cc\u4e70\u4e0b\u4e00\u4e2a\u5c0f\u4f0f\u7b14\uff0c\u8fd9\u91cc\u5176\u5b9e\u9664\u4e86\u6309\u94ae\u4f4d\u7f6e\u4e0d\u5bf9\uff0c`claude`\u662f\u6b63\u786e\u5b8c\u6210\u4e86\u7684\uff0c\u8fd9\u91cc\u5b8c\u5168\u662f\u6211\u7684\u95ee\u9898\u9020\u6210\u7684\uff0c\u4e0d\u8fc7\u4e5f\u8bc1\u660e\u6211\u771f\u7684\u662f\u4e2a\u4e00\u7a8d\u4e0d\u901a\u7684\u5c0f\u767d\uff0c\u54c8\u54c8\u54c8\u3002\\n\\n## \u7ea0\u6b63\u9519\u8bef\\n\\n\u6211\u544a\u8bc9\u5b83\u6211\u9047\u5230\u7684\u95ee\u9898\uff1a\\n\\n![1773414288066](image/ai-collaboration-and-technical-depth/1773414288066.png)\\n\\n\u5b83\u8ba4\u771f\u5206\u6790\u4e86\u51fa\u73b0\u7684bug\uff1a\\n\\n![1773414330696](image/ai-collaboration-and-technical-depth/1773414330696.png)\\n\\n\u597d\u7684\uff0c\u5230\u8fd9\u91cc\u4f60\u5c31\u660e\u767d\u4e3a\u4ec0\u4e48\u6211\u4f1a\u590d\u5236\u7684\u4e0d\u662fmd\u683c\u5f0f\u4e86\uff0c\u56e0\u4e3a\u6211\u542f\u52a8\u547d\u4ee4\u662f`npm run start`\uff0c\u662f\u7684\uff0c\u5c31\u662f\u6211\u524d\u9762\u63d0\u5230\u7684\uff0c\u6211\u53ea\u77e5\u9053\u8fd9\u4e2a\u542f\u52a8\u547d\u4ee4\u3002\\n\\n\u7136\u540e\u5b83\u6307\u51fa\u4e86\u6211\u7684\u9519\u8bef\uff0c\u8ba9\u6211\u7528\u6b63\u786e\u65b9\u5f0f\u542f\u52a8\\n\\n![1773414445763](image/ai-collaboration-and-technical-depth/1773414445763.png)\\n\\n\u6700\u540e\u4e5f\u6210\u529f\u5b9e\u73b0\u4e86\u8fd9\u4e2a\u63d2\u4ef6\u529f\u80fd\uff0c\u53ea\u7528\u4e86\u4e24\u8f6e\u5bf9\u8bdd\u3002\\n\\n\u4f46\u6709\u4e00\u4e2a\u95ee\u9898\u662f\uff0c\u6211\u4e0d\u77e5\u9053\u8fd9\u7b97\u4e0d\u7b97\u6210\u529f\uff0c\u6280\u672f\u6df1\u5ea6\u5728\u8fd9\u91cc\u7684\u4ef7\u503c\u5c31\u6765\u4e86\uff0c\u5f53\u7136\u4e5f\u53ef\u4ee5\u95eeAI\uff0c\u4f46\u6709\u81ea\u5df1\u7684\u5224\u65ad\u4f1a\u66f4\u8e0f\u5b9e\u3002\\n\\n## \u603b\u7ed3\u601d\u8003\\n\\n\u5728AI\u65f6\u4ee3\u4e0b\uff1a\\n\\n<mark style={{backgroundColor: '#fff3cd', padding: '0 4px', borderRadius: '3px'}}>\u529b\u91cf\u672c\u8eab\u5e76\u4e0d\u53ef\u6015\uff0c\u53ef\u6015\u7684\u662f\u5b83\u7684\u4e3b\u4eba</mark>\\n\\n\u867d\u7136\u6211\u901a\u8fc7\u5de5\u5177\u6280\u5de7\u7684\u4f7f\u7528\uff0c\u5b8c\u6210\u4e86\u8fd9\u6b21\u7684\u5f00\u53d1\uff0c\u4f46\u5982\u679c\u770btoken\u91cf\u548c\u65f6\u95f4\u5462\uff1a\\n\\n![1773414941231](image/ai-collaboration-and-technical-depth/1773414941231.png)\\n\\n\u662f\u7684\uff0c\u5b83\u8dd1\u4e86\u4e09\u5341\u591a\u5206\u949f\uff0c\u82b1\u8d39\u4e868\u7f8e\u91d1\uff0c\u7b97\u6210\u4eba\u6c11\u5e01\u5c31\u662f56\u5757\u6ca1\u4e86\uff0c\u8fd9\u6837\u8bf4\u53ef\u80fd\u6ca1\u6709\u611f\u89c9\uff0c\u6362\u53e5\u8bdd\u8bf4\uff1a\u82b1\u4e94\u5341\u5757\u52a0\u4e00\u4e2a\u6309\u94ae\uff0c\u662f\u4e0d\u662f\u542c\u8d77\u6765\u5c31\u5f88\u75db\u82e6\u4e86\u3002\\n\\n\u5982\u679c\u6709\u6280\u672f\u6df1\u5ea6\u5e76\u5584\u7528\u5de5\u5177\uff0c\u662f\u4e0d\u662f\u4e00\u6b21\u8981\u6c42\u76f4\u63a5\u8dd1\u5b8c\uff0c\u6839\u672c\u4e0d\u9700\u8981\u8fd9\u4e48\u591a\u65f6\u95f4\u548ctoken\u5462\u3002\\n\\n\u9879\u76ee\u7684\u5b8c\u6210\u662f\u4e00\u4e2a\u51fd\u6570\uff1a`y = kx + b`\\n\\nb\u662f\u5584\u7528\u5de5\u5177\uff0ck\u5c31\u662f\u6280\u672f\u6df1\u5ea6\u3002\"},{\"id\":\"mdx-blog-post\",\"metadata\":{\"permalink\":\"/blog/mdx-blog-post\",\"editUrl\":\"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/littlebear.md\",\"source\":\"@site/blog/littlebear.md\",\"title\":\"\u963f\u91cc\u5929\u6c60\u4e8c\u624b\u8f66\u4ef7\u683c\u9884\u6d4b\u6bd4\u8d5bTop2\u5206\u4eab\",\"description\":\"\u8fd9\u662f\u5173\u4e8e\u6211\u5728\u6bd4\u8d5b\u4e2d\u5982\u4f55\u4e00\u6b65\u6b65\u63d0\u5347\u5206\u6570\uff0c\u6700\u7ec8\u53d6\u5f97\u7b2c2\u540d\u6210\u7ee9\u65b9\u6848\u7684\u5fc3\u5f97\u5206\u4eab\",\"date\":\"2025-07-04T00:00:00.000Z\",\"tags\":[],\"readingTime\":15.89,\"hasTruncateMarker\":true,\"authors\":[],\"frontMatter\":{\"slug\":\"mdx-blog-post\",\"title\":\"\u963f\u91cc\u5929\u6c60\u4e8c\u624b\u8f66\u4ef7\u683c\u9884\u6d4b\u6bd4\u8d5bTop2\u5206\u4eab\",\"date\":\"2025-07-04T00:00:00.000Z\"},\"unlisted\":false,\"prevItem\":{\"title\":\"\u5584\u7528\u5de5\u5177\u5f25\u8865\u6280\u672f\u6df1\u5ea6\",\"permalink\":\"/blog/ai-collaboration-and-technical-depth\"}},\"content\":\"\u8fd9\u662f\u5173\u4e8e\u6211\u5728\u6bd4\u8d5b\u4e2d\u5982\u4f55\u4e00\u6b65\u6b65\u63d0\u5347\u5206\u6570\uff0c\u6700\u7ec8\u53d6\u5f97\u7b2c2\u540d\u6210\u7ee9\u65b9\u6848\u7684\u5fc3\u5f97\u5206\u4eab\\n\\n## \u524d\u8a00\\n\\n\x3c!-- truncate --\x3e\\n\\n\u5728\u521d\u6b65\u638c\u63e1\u7ecf\u5178\u795e\u7ecf\u7f51\u7edc\u7684\u57fa\u672c\u539f\u7406\u4e4b\u540e\uff0c\u5bfc\u5e08\u5411\u6211\u63a8\u8350\u4e86\u963f\u91cc\u4e91\u7684\u5929\u6c60\u6bd4\u8d5b\uff0c\u6211\u6000\u7740\u68c0\u9a8c\u81ea\u5df1\u5b66\u4e60\u6210\u679c\u7684\u5fc3\u6001\uff0c\u5f00\u59cb\u4e86\u8fd9\u6b21\u6bd4\u8d5b\u7684\u5f81\u7a0b\u3002\u6700\u540e\u4e5f\u662f\u53d6\u5f97\u4e86\u7b2c\u4e8c\u540d\uff0c\u867d\u7136\u9057\u61be\u5931\u53bb\u5929\u732b\u7cbe\u7075\uff08\u7b2c\u4e00\u540d\u5956\u54c1\uff09,\u4f46\u662f\u6211\u4e5f\u4ece\u8fd9\u6b21\u6bd4\u8d5b\u5b66\u5230\u4e86\u5f88\u591a\u4e1c\u897f\uff0c\u901a\u8fc7\u6bd4\u8d5b\u6211\u611f\u89c9\u5230\u81ea\u5df1\u6210\u957f\u4e86\u4e0d\u5c11\uff0c\u8bdd\u4e0d\u591a\u8bf4\uff0c\u5148\u4e0a\u56fe\u3002![1752052948201](image/littlebear/1752052948201.png)\\n\\n## \u521d\u59cb\u9636\u6bb5\\n\\n- \u8ff7\u832b\u4e0e\u8d77\u6b65\uff1a\u521a\u5f00\u59cb\u63a5\u89e6\u8d5b\u9898\u65f6\uff0c\u6211\u4e5f\u548c\u5176\u4ed6\u53c2\u8d5b\u8005\u4e00\u6837\u611f\u5230\u56f0\u60d1\uff0c\u4e0d\u77e5\u4ece\u4f55\u5165\u624b\u3002\u4e8e\u662f\uff0c\u6211\u51b3\u5b9a\u6309\u7167\u5929\u6c60\u63d0\u4f9b\u7684\u57fa\u51c6\u7ebf\uff08baseline\uff09\u6765\u8fd0\u884c\u57fa\u7840\u6a21\u578b\uff0c\u770b\u770b\u80fd\u83b7\u5f97\u591a\u5c11\u5206\u6570\u3002\\n- \u6311\u6218\u4e0e\u89e3\u51b3\uff1a\u7136\u800c\uff0c\u8fd0\u884c\u57fa\u51c6\u7ebf\u6a21\u578b\u7684\u8fc7\u7a0b\u5e76\u4e0d\u987a\u5229\uff0c\u8bad\u7ec3\u65f6\u95f4\u5f02\u5e38\u6f2b\u957f\u3002\u5c3d\u7ba1\u6211\u4f7f\u7528\u7684\u662f\u6027\u80fd\u4e0d\u9519\u76844060\u663e\u5361\uff0c\u672c\u5730\u8bad\u7ec3\u901f\u5ea6\u4ecd\u7136\u7f13\u6162\u3002\u6700\u7ec8\uff0c\u901a\u8fc7\u7b97\u529b\u5e73\u53f0\u7684\u5e2e\u52a9\uff0c\u6211\u6210\u529f\u8dd1\u901a\u4e86\u6a21\u578b\uff0c\u4f46\u5f97\u5206\u4ec5\u4e3a700\u5de6\u53f3\u3002\\n\\n## \u63d0\u5347\u5206\u6570\\n\\n- \u521d\u6b65\u76ee\u6807\uff1a\u6700\u521d\uff0c\u6211\u8bbe\u5b9a\u7684\u76ee\u6807\u662f\u8d85\u8d8a\u5b98\u65b9\u57fa\u51c6\u7ebf\u7684\u5206\u6570\u3002\u7136\u800c\uff0c\u5f53\u6211\u770b\u5230\u6392\u884c\u699c\u4e0a\u7684\u9ad8\u5206\u65f6\uff0c\u5fc3\u4e2d\u71c3\u8d77\u4e86\u4e0d\u670d\u8f93\u7684\u6597\u5fd7\u3002\\n- \u8d44\u6599\u67e5\u9605\uff1a\u4e3a\u4e86\u63d0\u5347\u5206\u6570\uff0c\u6211\u5f00\u59cb\u5e7f\u6cdb\u67e5\u9605\u8d44\u6599\uff0c\u5305\u62ecCSDN\u548c\u963f\u91cc\u8bba\u575b\uff0c\u5e0c\u671b\u80fd\u4ece\u524d\u8f88\u7684\u7ecf\u9a8c\u4e2d\u627e\u5230\u63d0\u5347\u6a21\u578b\u6027\u80fd\u7684\u65b9\u6cd5\u3002\\n\\n## \u5b66\u4e60\u4e0e\u5b9e\u8df5\\n\\n- \u5b66\u4e60\u8def\u7ebf\uff1a\u5728\u62e5\u6709\u57fa\u7840\u6a21\u578b\u540e\uff0c\u6211\u5c1d\u8bd5\u5e94\u7528\u6240\u5b66\u7684\u63d0\u5347\u6a21\u578b\u6027\u80fd\u7684\u65b9\u6cd5\uff0c\u5982\u63a7\u5236\u53d8\u91cf\u6cd5\u8fdb\u884c\u8c03\u4f18\uff0c\u5e76\u5c06\u7f51\u7edc\u7ed3\u6784\u66f4\u6362\u4e3aResNet\u3002\u7136\u800c\uff0c\u6548\u679c\u5e76\u4e0d\u7406\u60f3\uff0c\u6709\u65f6\u751a\u81f3\u51fa\u73b0\u4e0a\u5343\u5206\u7684\u5f02\u5e38\u60c5\u51b5\u3002\\n- \u524d\u8f88\u7ecf\u9a8c\uff1a\u5728\u5bfc\u5e08\u7684\u63a8\u8350\u4e0b\uff0c\u6211\u89c2\u770b\u4e86B\u7ad9\u4e0a\u7684\u9876\u7ea7\u65b9\u6848\u5206\u4eab\u89c6\u9891\uff0c\u4ece\u4e2d\u4e86\u89e3\u5230\u7279\u5f81\u5de5\u7a0b\u7684\u91cd\u8981\u6027\u3002\u6211\u82b1\u8d39\u6570\u65e5\u65f6\u95f4\u6df1\u5165\u5b66\u4e60\uff0c\u5e76\u7ed3\u5408\u81ea\u8eab\u7406\u89e3\u8fdb\u884c\u4f18\u5316\u3002\\n\\n## \u7279\u5f81\u5de5\u7a0b\\n\\n- \u91cd\u8981\u6027\u8ba4\u8bc6\uff1a\u901a\u8fc7\u5b66\u4e60\uff0c\u6211\u8ba4\u8bc6\u5230\u6570\u636e\u9884\u5904\u7406\u548c\u7279\u5f81\u5de5\u7a0b\u624d\u662f\u51b3\u5b9a\u6a21\u578b\u4e0a\u9650\u7684\u5173\u952e\u56e0\u7d20\uff0c\u800c\u7f51\u7edc\u8c03\u4f18\u53ea\u662f\u9526\u4e0a\u6dfb\u82b1\u3002\\n- \u5b9e\u8df5\u6548\u679c\uff1a\u5c06\u91cd\u70b9\u8f6c\u5411\u7279\u5f81\u5de5\u7a0b\u540e\uff0c\u5373\u4f7f\u4f7f\u7528\u7b80\u5355\u7684\u5168\u8fde\u63a5\u795e\u7ecf\u7f51\u7edc\uff0c\u6548\u679c\u4e5f\u663e\u8457\u63d0\u5347\uff0c\u5206\u6570\u5927\u5e45\u4e0a\u5347\uff0c\u4f7f\u6211\u8dc3\u5c45\u6392\u884c\u699c\u524d\u5217\u3002\\n\\n## \u6a21\u578b\u878d\u5408\\n\\n- \u7406\u8bba\u5e94\u7528\uff1a\u53d7\u5230\u968f\u673a\u68ee\u6797\u8bba\u6587\u7684\u542f\u53d1\uff0c\u6211\u51b3\u5b9a\u5c1d\u8bd5\u6a21\u578b\u878d\u5408\uff0c\u5373\u901a\u8fc7\u7ec4\u5408\u591a\u4e2a\u5f31\u6a21\u578b\u6765\u6784\u5efa\u5f3a\u6a21\u578b\u3002\\n- \u5177\u4f53\u64cd\u4f5c\uff1a\u7ecf\u8fc7\u4e0e\u6811\u6a21\u578b\u7684\u52a0\u6743\u878d\u5408\uff0c\u6211\u7684\u5206\u6570\u8fdb\u4e00\u6b65\u63d0\u5347\u81f3406\u3002\u968f\u540e\uff0c\u901a\u8fc7\u51ef\u660e\u521d\u59cb\u5316\u53c2\u6570\u548c\u6dfb\u52a0\u65b0\u7684\u76f8\u5173\u6027\u7279\u5f81\u4ea4\u4e92\uff0c\u5206\u6570\u7a33\u5b9a\u5728398\u3002\\n\\n---\\n\\n\u4ee5\u4e0b\u662f\u6a21\u578b\u7684\u8be6\u7ec6\u4ecb\u7ecd\\n\\n## 1. \u7279\u5f81\u5de5\u7a0b\\n\\n\u7279\u5f81\u5de5\u7a0b\u662f\u673a\u5668\u5b66\u4e60\u6d41\u7a0b\u4e2d\u81f3\u5173\u91cd\u8981\u7684\u4e00\u6b65\uff0c\u5b83\u901a\u8fc7\u4ece\u539f\u59cb\u6570\u636e\u4e2d\u63d0\u53d6\u3001\u8f6c\u6362\u548c\u521b\u5efa\u65b0\u7279\u5f81\uff0c\u4ee5\u63d0\u9ad8\u6a21\u578b\u7684\u9884\u6d4b\u80fd\u529b\u3002\\n\\n### 1.1 \u6570\u636e\u52a0\u8f7d\u4e0e\u5408\u5e76\\n\\n\u9996\u5148\uff0c\u52a0\u8f7d\u4e86\u8bad\u7ec3\u96c6\u548c\u6d4b\u8bd5\u96c6\u6570\u636e\uff0c\u5e76\u5c06\u5b83\u4eec\u5408\u5e76\u4ee5\u4fbf\u7edf\u4e00\u5904\u7406\u3002\\n\\n```python\\n# \u8def\u5f84\u8bbe\u7f6e\\ninput_path = '''./datasets/'''\\noutput_path = '''./prediction_result/'''\\nuser_data_path = '''./user_data/'''\\nos.makedirs(output_path, exist_ok=True)\\nos.makedirs(user_data_path, exist_ok=True)\\n\\n# \u8bfb\u53d6\u6570\u636e\\nTrain_data = pd.read_csv(input_path+'''used_car_train_20200313.csv''', sep=''' ''')\\nTest_data = pd.read_csv(input_path+'''used_car_testB_20200421.csv''', sep=''' ''')\\n\\n# \u5408\u5e76\u6570\u636e\u65b9\u4fbf\u5904\u7406\\ndf = pd.concat([Train_data, Test_data], ignore_index=True)\\n\\n```\\n\\n### 1.2 \u5f02\u5e38\u6570\u636e\u5904\u7406\\n\\n\u5bf9\u6570\u636e\u4e2d\u7684\u5f02\u5e38\u503c\u8fdb\u884c\u4fee\u6b63\uff0c\u5305\u62ec\uff1a\\n\\n- \u5220\u9664 `seller` \u4e3a1\u7684\u5f02\u5e38\u8bb0\u5f55\u3002\\n- \u5c06 `power` \u5927\u4e8e600\u7684\u503c\u622a\u65ad\u4e3a600\u3002\\n- \u5c06 `v_14` \u5927\u4e8e4\u7684\u503c\u4fee\u6b63\u4e3a4\u3002\\n\\n```python\\n# \u5904\u7406\u5f02\u5e38\u6570\u636e\\ndf.drop(df[df['''seller'''] == 1].index, inplace=True)\\ndf_copy = df.copy()\\n# \u53ea\u5bf9power>600\u7684\u503c\u8fdb\u884c\u622a\u65ad\u5904\u7406\\ndf['''power'''][df['''power''']>600]=600\\n\\n# \u5904\u7406v_14\u5f02\u5e38\u503c\\nv14_outliers = (df['''v_14'''] > 4).sum()\\nif v14_outliers > 0:\\n    print(f\\\"    \u4fee\u6b63 {v14_outliers} \u6761v_14>4\u7684\u5f02\u5e38\u503c\\\")\\n    df['''v_14'''][df['''v_14'''] > 4] = 4\\n```\\n\\n### 1.3 `notRepairedDamage` \u7279\u5f81\u5904\u7406\\n\\n\u5c06 `notRepairedDamage` \u5217\u4e2d\u7684 '-' \u66ff\u6362\u4e3a 0.5\uff0c\u7136\u540e\u8fdb\u884c\u6807\u7b7e\u7f16\u7801\u3002\\n\\n```python\\n# notRepairedDamage\u5904\u7406\\ndf.replace(to_replace = '''-''', value = 0.5, inplace = True)\\nle = LabelEncoder()\\ndf['''notRepairedDamage'''] = le.fit_transform(df['''notRepairedDamage'''].astype(str))\\n```\\n\\n### 1.4 \u65e5\u671f\u7279\u5f81\u5de5\u7a0b\\n\\n\u4ece `regDate` (\u6ce8\u518c\u65e5\u671f) \u548c `creatDate` (\u521b\u5efa\u65e5\u671f/\u4ea4\u6613\u65e5\u671f) \u4e2d\u63d0\u53d6\u5e74\u3001\u6708\u3001\u65e5\u4fe1\u606f\uff0c\u5e76\u8ba1\u7b97\uff1a\\n\\n- `car_age_day` (\u8f66\u9f84\u5929\u6570)\\n- `car_age_year` (\u8f66\u9f84\u5e74\u6570)\\n- `used_time_month` (\u4f7f\u7528\u6708\u6570)\\n- `is_weekend` (\u4ea4\u6613\u65e5\u671f\u662f\u5426\u4e3a\u5468\u672b)\\n- `depreciation_year` (\u57fa\u4e8e\u8f66\u9f84\u7684\u6298\u65e7\u7387\uff0c\u4e00\u4e2a\u81ea\u5b9a\u4e49\u51fd\u6570)\\n\\n```python\\n# \u65e5\u671f\u5904\u7406\\nfrom datetime import datetime\\ndef date_process(x):\\n    year = int(str(x)[:4])\\n    month = int(str(x)[4:6])\\n    day = int(str(x)[6:8])\\n    if month < 1:\\n        month = 1\\n    date = datetime(year, month, day)\\n    return date\\n\\ndf['''regDates'''] = df['''regDate'''].apply(date_process)\\ndf['''creatDates'''] = df['''creatDate'''].apply(date_process)\\ndf['''regDate_year'''] = df['''regDates'''].dt.year\\ndf['''regDate_month'''] = df['''regDates'''].dt.month\\ndf['''regDate_day'''] = df['''regDates'''].dt.day\\ndf['''creatDate_year'''] = df['''creatDates'''].dt.year\\ndf['''creatDate_month'''] = df['''creatDates'''].dt.month\\ndf['''creatDate_day'''] = df['''creatDates'''].dt.day\\ndf['''car_age_day'''] = (df['''creatDates'''] - df['''regDates''']).dt.days\\ndf['''car_age_year'''] = round(df['''car_age_day'''] / 365, 1)\\n# \u65b0\u589e\u7279\u5f81\uff1a\u6708\u6570\u8ba1\u7b97\\ndf['''used_time_month'''] = round(df['''car_age_day'''] / 30, 3)\\n# \u65b0\u589e\u7279\u5f81\uff1a\u4ea4\u6613\u65e5\u671f\u662f\u5426\u4e3a\u5468\u672b\\ndf['''is_weekend'''] = df['''creatDates'''].dt.dayofweek.apply(lambda x: 1 if x in(5,6) else 0)\\n# \u65b0\u589e\u7279\u5f81\uff1a\u4f7f\u7528\u5e74\u9650\u6298\u65e7\u7387\\ndef depreciation_year(year):\\n    if year <= 3:\\n        return 1 - year * 0.15\\n    elif year > 3 and year <= 7:\\n        return 0.55 - (year-3) * 0.1\\n    elif year > 7 and year <= 10:\\n        return 0.25 - (year-7) * 0.05\\n    else:\\n        return 0\\ndf['''depreciation_year'''] = df['''car_age_year'''].apply(lambda x: depreciation_year(x))\\n```\\n\\n### 1.5 `name_count` \u7279\u5f81\\n\\n\u8ba1\u7b97\u6bcf\u4e2a `name` (\u8f66\u8f86\u540d\u79f0) \u51fa\u73b0\u7684\u6b21\u6570\uff0c\u8fd9\u53ef\u4ee5\u4f5c\u4e3a\u8861\u91cf\u8be5\u540d\u79f0\u70ed\u95e8\u7a0b\u5ea6\u7684\u7279\u5f81\u3002\\n\\n```python\\n# name_count\u7279\u5f81\\ndf['''name_count'''] = df.groupby(['''name'''])['''SaleID'''].transform('''count''')\\n```\\n\\n### 1.6 \u7f3a\u5931\u503c\u586b\u5145\\n\\n\u4f7f\u7528\u4f17\u6570\u586b\u5145\u9664\u7279\u5b9a\u5217\u5916\u6240\u6709\u7279\u5f81\u7684\u7f3a\u5931\u503c\u3002\\n\\n```python\\n# \u7528\u4f17\u6570\u586b\u5145\u7f3a\u5931\u503c\\nfor col in df.columns:\\n    if col in ['''SaleID''', '''name''', '''regDate''', '''creatDate''', '''price''', \\n                                                        '''seller''', '''offerType''', '''train''', '''regDates''', '''creatDates''']:\\n        continue\\n    if df[col].dtype == '''object''' or df[col].dtype == '''int64''' or df[col].dtype == '''float64''':\\n        mode_val = df[col].mode()[0]\\n        df[col].fillna(mode_val, inplace=True)\\n```\\n\\n### 1.7 \u57ce\u5e02\u4fe1\u606f\u4e0e\u5e74\u5e73\u5747\u91cc\u7a0b\\n\\n- \u4ece `regionCode` (\u90ae\u7f16) \u4e2d\u63d0\u53d6 `city` (\u57ce\u5e02) \u4fe1\u606f\u3002\\n- \u8ba1\u7b97 `kilometer_everyear` (\u5e74\u5e73\u5747\u91cc\u7a0b)\u3002\\n\\n```python\\n# \u65b0\u589e\u7279\u5f81: \u4ece\u90ae\u7f16\u63d0\u53d6\u57ce\u5e02\u4fe1\u606f\\ndf['''city'''] = df['''regionCode'''].apply(lambda x: str(x)[:-3])\\ndf['''city'''].replace(''''''', '''0''', inplace=True)\\n# \u8ba1\u7b97\u5e74\u5e73\u5747\u91cc\u7a0b\\ndf['''kilometer_everyear'''] = round(1000 * df['''kilometer'''] / df['''car_age_year'''].clip(lower=0.1), 3)\\ndf['''kilometer_everyear'''].fillna(df['''kilometer_everyear'''].median(), inplace=True)\\n# ... existing code ...\\n```\\n\\n### 1.8 \u8ba1\u6570\u7f16\u7801\u7279\u5f81 (Count Features)\\n\\n\u5bf9\u591a\u4e2a\u7c7b\u522b\u7279\u5f81\uff08`model`, `brand`, `bodyType`, `fuelType`, `gearbox`, `regDate_year`\uff09\u8fdb\u884c\u8ba1\u6570\u7f16\u7801\uff0c\u5373\u8ba1\u7b97\u6bcf\u4e2a\u7c7b\u522b\u503c\u7684\u51fa\u73b0\u6b21\u6570\u3002\\n\\n```python\\n# \u65b0\u589e\u7279\u5f81: \u8ba1\u6570\u7279\u5f81(\u70ed\u95e8\u7a0b\u5ea6)\\ndef count_features(df, feat_cols):\\n    for feat in tqdm(feat_cols, desc=\\\"\u8ba1\u6570\u7f16\u7801\\\"):\\n        df[feat + '''_count'''] = df[feat].map(df[feat].value_counts())\\n    return df\\ncount_feature_list = ['''model''', '''brand''', '''bodyType''', '''fuelType''', '''gearbox''', '''regDate_year''']\\ndf = count_features(df, count_feature_list)\\n```\\n\\n### 1.9 \u54c1\u724c\u548c\u8f66\u578b\u7edf\u8ba1\u7279\u5f81\\n\\n\u8fd9\u90e8\u5206\u521b\u5efa\u4e86\u4e30\u5bcc\u7684\u7edf\u8ba1\u7279\u5f81\uff0c\u5305\u62ec `brand` (\u54c1\u724c) \u548c `model` (\u8f66\u578b) \u4e0b\u7684\u8f66\u8f86\u6570\u91cf\u3001\u4ef7\u683c\u7684\u6700\u5927\u503c\u3001\u4e2d\u4f4d\u6570\u3001\u6700\u5c0f\u503c\u3001\u6807\u51c6\u5dee\u548c\u5e73\u5747\u503c\u3002\u8fd9\u4e9b\u7279\u5f81\u80fd\u591f\u6355\u83b7\u54c1\u724c\u548c\u8f66\u578b\u5bf9\u4ef7\u683c\u7684\u5f71\u54cd\u3002\\n\\n```python\\n# \u65b0\u589e\u7279\u5f81: \u54c1\u724c\u548c\u8f66\u578b\u7edf\u8ba1\u7279\u5f81\\n# \u786e\u5b9a\u8bad\u7ec3\u96c6\u7684\u7d22\u5f15\u8303\u56f4\\ntrain_num = sum(df['''SaleID'''].isin(Train_data['''SaleID''']))\\ntrain_part = df_copy.iloc[:train_num].copy()\\n\\n# \u54c1\u724c\u7edf\u8ba1\\ntrain_gb = train_part.groupby(\\\"brand\\\")\\nall_info = {}\\nfor kind, kind_data in tqdm(train_gb, desc=\\\"\u54c1\u724c\u7edf\u8ba1\\\"):\\n    info = {}\\n    kind_data = kind_data[kind_data['''price'''] > 0]\\n    if len(kind_data) > 0:\\n        info['''brand_amount'''] = len(kind_data)\\n        info['''brand_price_max'''] = kind_data.price.max()\\n        info['''brand_price_median'''] = kind_data.price.median()\\n        info['''brand_price_min'''] = kind_data.price.min()\\n        info['''brand_price_std'''] = kind_data.price.std()\\n        info['''brand_price_average'''] = round(kind_data.price.sum() / (len(kind_data) + 1), 2)\\n        all_info[kind] = info\\nbrand_fe = pd.DataFrame(all_info).T.reset_index().rename(columns={\\\"index\\\": \\\"brand\\\"})\\ndf = df.merge(brand_fe, how='''left''', on='''brand''')\\n\\n# \u8f66\u578b\u7edf\u8ba1 (\u4e0e\u54c1\u724c\u7edf\u8ba1\u7c7b\u4f3c)\\ntrain_gb = train_part.groupby(\\\"model\\\")\\nall_info = {}\\nfor kind, kind_data in tqdm(train_gb, desc=\\\"\u8f66\u578b\u7edf\u8ba1\\\"):\\n    info = {}\\n    kind_data = kind_data[kind_data['''price'''] > 0]\\n    if len(kind_data) > 0:\\n        info['''model_amount'''] = len(kind_data)\\n        info['''model_price_max'''] = kind_data.price.max()\\n        info['''model_price_median'''] = kind_data.price.median()\\n        info['''model_price_min'''] = kind_data.price.min()\\n        info['''model_price_std'''] = kind_data.price.std()\\n        info['''model_price_average'''] = round(kind_data.price.sum() / (len(kind_data) + 1), 2)\\n        all_info[kind] = info\\nmodel_fe = pd.DataFrame(all_info).T.reset_index().rename(columns={\\\"index\\\": \\\"model\\\"})\\ndf = df.merge(model_fe, how='''left''', on='''model''')\\n```\\n\\n### 1.10 \u7c7b\u522b\u7279\u5f81\u7edf\u8ba1\u805a\u5408\\n\\n\u5bf9 `kilometer`, `fuelType`, `bodyType` \u8fd9\u4e09\u4e2a\u7c7b\u522b\u7279\u5f81\uff0c\u8ba1\u7b97\u5b83\u4eec\u4e0e `price` \u76f8\u5173\u7684\u5404\u79cd\u7edf\u8ba1\u91cf\uff08\u8ba1\u6570\u3001\u6700\u5927\u503c\u3001\u4e2d\u4f4d\u6570\u3001\u6700\u5c0f\u503c\u3001\u603b\u548c\u3001\u6807\u51c6\u5dee\u3001\u5e73\u5747\u503c\uff09\u3002\\n\\n```python\\n# \u65b0\u589e\u7279\u5f81: 5\u4e2a\u7c7b\u522b\u7279\u5f81\u76847\u79cd\u7edf\u8ba1\u91cf\u8ba1\u7b97\\n# \u53ea\u5bf9kilometer, fuelType, bodyType\u8fdb\u884c\u7edf\u8ba1\uff0cbrand\u548cmodel\u5df2\u7ecf\u5728\u4e0a\u9762\u5904\u7406\u8fc7\u4e86\\ncat_cols = ['''kilometer''', '''fuelType''', '''bodyType''']\\nfor col in tqdm(cat_cols, desc=\\\"\u7c7b\u522b\u7edf\u8ba1\u7279\u5f81\\\"):\\n    t = train_part.groupby(col, as_index=False)['''price'''].agg({\\n        col+'''_count''':'''count''',\\n        col+'''_price_max''':'''max''',\\n        col+'''_price_median''':'''median''',\\n        col+'''_price_min''':'''min''',\\n        col+'''_price_sum''':'''sum''',\\n        col+'''_price_std''':'''std''',\\n        col+'''_price_mean''':'''mean'''\\n    })\\n    df = pd.merge(df, t, on=col, how='''left''')\\n\\n# kilometer\u4e0epower\u7684\u4ea4\u53c9\u7edf\u8ba1\\nkk = ['''kilometer''', '''power''']\\nt1 = train_part.groupby(kk[0], as_index=False)[kk[1]].agg({\\n    kk[0]+'''_'''+kk[1]+'''_count''':'''count''',\\n    kk[0]+'''_'''+kk[1]+'''_max''':'''max''',\\n    kk[0]+'''_'''+kk[1]+'''_median''':'''median''',\\n    kk[0]+'''_'''+kk[1]+'''_min''':'''min''',\\n    kk[0]+'''_'''+kk[1]+'''_sum''':'''sum''',\\n    kk[0]+'''_'''+kk[1]+'''_std''':'''std''',\\n    kk[0]+'''_'''+kk[1]+'''_mean''':'''mean'''\\n})\\ndf = pd.merge(df, t1, on=kk[0], how='''left''')\\n```\\n\\n### 1.11 \u7c7b\u522b\u4e0e\u6570\u503c\u4ea4\u53c9\u7279\u5f81\\n\\n\u521b\u5efa\u7c7b\u522b\u7279\u5f81 (`model`, `brand`, `bodyType`) \u4e0e\u6570\u503c\u7279\u5f81 (`power`, `kilometer`, `v_0`, `v_3`, `v_8`, `v_12`) \u7684\u4ea4\u53c9\u7edf\u8ba1\u7279\u5f81\uff0c\u5305\u62ec\u6bcf\u7ec4\u7684\u6700\u5927\u503c\u3001\u6700\u5c0f\u503c\u3001\u5e73\u5747\u503c\u548c\u6807\u51c6\u5dee\u3002\\n\\n```python\\n# \u65b0\u589e\u7279\u5f81: \u7c7b\u522b\u4e0e\u6570\u503c\u4ea4\u53c9\u7279\u5f81\\ndef cross_cat_num(df, cat_col, num_col):\\n    for f1 in tqdm(cat_col, desc=\\\"\u4ea4\u53c9\u7279\u5f81\\\"):\\n        g = df.groupby(f1, as_index=False)\\n        for f2 in num_col:\\n            feat = g[f2].agg({\\n                f'{f1}_{f2}_max': '''max''', \\n                f'{f1}_{f2}_min': '''min''',\\n                f'{f1}_{f2}_mean': '''mean''',\\n                f'{f1}_{f2}_std': '''std'''\\n            })\\n            df = df.merge(feat, on=f1, how='''left''')\\n    return df\\n\\ncross_cat = ['''model''', '''brand''', '''bodyType''']\\ncross_num = ['''power''', '''kilometer''', '''v_0''', '''v_3''', '''v_8''', '''v_12''']\\ndf = cross_cat_num(df, cross_cat, cross_num)\\n```\\n\\n### 1.12 \u66f4\u4e30\u5bcc\u7684\u7279\u5f81\u4ea4\u4e92\\n\\n\u521b\u5efa\u4e86\u6570\u503c\u7279\u5f81 (`v_0`, `v_3`, `v_8`, `v_12`) \u4e4b\u95f4\u7684\u4e58\u79ef\u3001\u52a0\u6cd5\u3001\u51cf\u6cd5\u7279\u5f81\uff0c\u4ee5\u53ca\u8fd9\u4e9b `v_` \u7279\u5f81\u4e0e `car_age_year` \u7684\u4e58\u79ef\u7279\u5f81\uff0c\u8fdb\u4e00\u6b65\u4e30\u5bcc\u4e86\u6a21\u578b\u7684\u8f93\u5165\u3002\\n\\n```python\\n# \u65b0\u589e\u7279\u5f81: \u66f4\u4e30\u5bcc\u7684\u7279\u5f81\u4ea4\u4e92\u65b9\u5f0f\\nnum_cols = [0, 3, 8, 12]  # \u76f8\u5173\u6027\u8f83\u9ad8\u7684\u7279\u5f81\\n\\nfor i in tqdm(num_cols, desc=\\\"    * \u4e58\u79ef\u7279\u5f81\\\"):\\n    for j in num_cols:\\n        df['''new'+str(i)+'''*'+str(j)] = df['''v_'+str(i)] * df['''v_'+str(j)]\\n\\nfor i in tqdm(num_cols, desc=\\\"    * \u52a0\u6cd5\u7279\u5f81\\\"):\\n    for j in num_cols:\\n        df['''new'+str(i)+'''+str(j)] = df['''v_'+str(i)] + df['''v_'+str(j)]\\n      \\nfor i in tqdm(num_cols, desc=\\\"    * \u51cf\u6cd5\u7279\u5f81\\\"):\\n    for j in num_cols:\\n        df['''new'+str(i)+'''-'+str(j)] = df['''v_'+str(i)] - df['''v_'+str(j)]\\n\\nfor i in tqdm(range(15), desc=\\\"    * \u8f66\u9f84\u4ea4\u4e92\u7279\u5f81\\\"):\\n    df['''new'+str(i)+'''*year'''] = df['''v_'+str(i)] * df['''car_age_year''']\\n```\\n\\n### 1.13 \u7279\u5f81\u5f52\u4e00\u5316\\n\\n\u4f7f\u7528 `MinMaxScaler` \u5bf9\u6240\u6709\u6570\u503c\u7279\u5f81\u8fdb\u884c\u5f52\u4e00\u5316\u5904\u7406\uff0c\u5c06\u5b83\u4eec\u7f29\u653e\u5230 [0, 1] \u7684\u8303\u56f4\uff0c\u8fd9\u6709\u52a9\u4e8e\u795e\u7ecf\u7f51\u7edc\u7684\u8bad\u7ec3\u3002\\n\\n```python\\n# \u7279\u5f81\u5f52\u4e00\u5316\\n# \u6240\u6709\u7279\u5f81\u5217\uff08\u9664\u4e86\u4e00\u4e9b\u7279\u6b8a\u5217\uff09\\nfeature_cols = [col for col in df.columns if col not in ['''SaleID''', '''name''', '''regDate''', '''creatDate''', '''price''', \\n                                                        '''seller''', '''offerType''', '''train''', '''regDates''', '''creatDates''']]\\n\\nprint(f\\\"    \u7279\u5f81\u603b\u6570: {len(feature_cols)}\\\")\\n\\n# \u5c06\u6240\u6709\u7279\u5f81\u89c4\u8303\u5230\u76f8\u540c\u5c3a\u5ea6\\nscaler = MinMaxScaler()\\nscaler.fit(df[feature_cols].values)\\ndf[feature_cols] = df[feature_cols].fillna(0)  # \u4fdd\u8bc1\u7279\u5f81\u65e0NaN\\n\\n# \u5f52\u4e00\u5316\\ndf_scaled = scaler.transform(df[feature_cols].values)\\ndf_scaled = np.nan_to_num(df_scaled)  # \u4fdd\u8bc1\u5f52\u4e00\u5316\u540e\u65e0NaN\\n\\n# \u5207\u5206\u6570\u636e\\ntrain_num = sum(df['''SaleID'''].isin(Train_data['''SaleID''']))\\nX_data = df_scaled[:train_num]\\nY_data = np.array(df_copy['''price'''][:train_num])\\nY_data = np.nan_to_num(Y_data)  # \u4fdd\u8bc1\u6807\u7b7e\u65e0NaN\\nX_test = df_scaled[train_num:]\\n```\\n\\n## 2. \u795e\u7ecf\u7f51\u7edc\u6a21\u578b (Neural Network Model)\\n\\n\u6211\u6784\u5efa\u4e86\u4e00\u4e2a\u975e\u5e38\u7b80\u5355\u7684\u5168\u8fde\u63a5\u795e\u7ecf\u7f51\u7edc\uff0c\u867d\u7136\u7b80\u5355\uff0c\u4f46\u662f\u6548\u679c\u8fd8\u662f\u4e0d\u9519\u7684\uff0c\u8bad\u7ec3\u901f\u5ea6\u4e5f\u8fd8\u53ef\u4ee5\uff0c\u8bad\u7ec3\u4e00\u8f6e\u5927\u698210\u5206\u949f\u4ee5\u5185\uff0c\u76f8\u6bd4\u4e8e\u590d\u6742\u7684\u6b8b\u5dee\u7f51\u7edc\uff0c\u8282\u7701\u4e86\u4e0d\u5c11\u8bad\u7ec3\u65f6\u95f4\u3002\\n\\n### 2.1 `NeuralNetwork` \u6a21\u578b\u5b9a\u4e49\\n\\n\u8fd9\u662f\u4e00\u4e2a\u4e94\u5c42\u7684\u5168\u8fde\u63a5\u795e\u7ecf\u7f51\u7edc\uff0c\u4f7f\u7528 `ReLU` \u4f5c\u4e3a\u6fc0\u6d3b\u51fd\u6570\u3002\\n\\n- **\u8f93\u5165\u5c42**: `input_dim` (\u7279\u5f81\u6570\u91cf)\\n- **\u9690\u85cf\u5c42**: 512 -> 256 -> 128 -> 64\\n- **\u8f93\u51fa\u5c42**: 1 (\u7528\u4e8e\u56de\u5f52\u9884\u6d4b\u4ef7\u683c)\\n\\n\u6a21\u578b\u4e2d\u8fd8\u5305\u542b\u4e86L2\u6b63\u5219\u5316 (`self.l2_reg`) \u4ee5\u9632\u6b62\u8fc7\u62df\u5408\uff0c\u5e76\u4e14\u4f7f\u7528\u4e86\u51ef\u660e\u521d\u59cb\u5316\uff08He\u521d\u59cb\u5316\uff09\u6765\u521d\u59cb\u5316\u6743\u91cd\uff0c\u5c06\u504f\u7f6e\u521d\u59cb\u5316\u4e3a0\u3002\\n\\n```python\\n# \u5b9a\u4e49PyTorch\u795e\u7ecf\u7f51\u7edc\u6a21\u578b\\nclass NeuralNetwork(nn.Module):\\n    def __init__(self, input_dim):\\n        super(NeuralNetwork, self).__init__()\\n        self.fc1 = nn.Linear(input_dim, 512)\\n        self.fc2 = nn.Linear(512, 256)\\n        self.fc3 = nn.Linear(256, 128)\\n        self.fc4 = nn.Linear(128, 64)\\n        self.fc5 = nn.Linear(64, 1)\\n        self.relu = nn.ReLU()\\n      \\n        # \u6dfb\u52a0L2\u6b63\u5219\u5316\\n        self.l2_reg = 0.05  # \u589e\u5927\u6b63\u5219\u5316\u53c2\u6570\u4ee5\u9002\u5e94\u66f4\u9ad8\u7ef4\u5ea6\u7684\u7279\u5f81\\n      \\n        # \u5e94\u7528\u51ef\u660e\u521d\u59cb\u5316\uff08He\u521d\u59cb\u5316\uff09\\n        nn.init.kaiming_normal_(self.fc1.weight, nonlinearity='''relu''')\\n        nn.init.kaiming_normal_(self.fc2.weight, nonlinearity='''relu''')\\n        nn.init.kaiming_normal_(self.fc3.weight, nonlinearity='''relu''')\\n        nn.init.kaiming_normal_(self.fc4.weight, nonlinearity='''relu''')\\n        nn.init.kaiming_normal_(self.fc5.weight, nonlinearity='''relu''')\\n      \\n        # \u521d\u59cb\u5316\u504f\u7f6e\u4e3a0\\n        nn.init.zeros_(self.fc1.bias)\\n        nn.init.zeros_(self.fc2.bias)\\n        nn.init.zeros_(self.fc3.bias)\\n        nn.init.zeros_(self.fc4.bias)\\n        nn.init.zeros_(self.fc5.bias)\\n      \\n    def forward(self, x):\\n        x = self.relu(self.fc1(x))\\n        x = self.relu(self.fc2(x))\\n        x = self.relu(self.fc3(x))\\n        x = self.relu(self.fc4(x))\\n        x = self.fc5(x)\\n        return x\\n  \\n    def get_l2_loss(self):\\n        l2_loss = 0.0\\n        for param in self.parameters():\\n            l2_loss += torch.norm(param, 2)\\n        return self.l2_reg * l2_loss\\n\\n```\\n\\n### 2.2 `LRScheduler` \u5b66\u4e60\u7387\u8c03\u5ea6\u5668\\n\\n\u8be5\u8c03\u5ea6\u5668\u5728\u7279\u5b9a\u8bad\u7ec3\u8f6e\u6b21\uff08200, 300, 360, 420\uff09\u964d\u4f4e\u5b66\u4e60\u7387\uff0c\u8fd9\u6709\u52a9\u4e8e\u6a21\u578b\u5728\u8bad\u7ec3\u540e\u671f\u66f4\u597d\u5730\u6536\u655b\u3002\\n\\n```python\\n# \u5b66\u4e60\u7387\u8c03\u5ea6\u5668\\nclass LRScheduler:\\n    def __init__(self, optimizer):\\n        self.optimizer = optimizer\\n      \\n    def step(self, epoch):\\n        lr = self.optimizer.param_groups[0]['''lr''']\\n        if epoch == 200:\\n            lr *= 0.5\\n        elif epoch == 300:\\n            lr *= 0.2\\n        elif epoch == 360:\\n            lr *= 0.1\\n        elif epoch == 420:\\n            lr *= 0.1\\n      \\n        for param_group in self.optimizer.param_groups:\\n            param_group['''lr'''] = lr\\n      \\n        return lr\\n```\\n\\n### 2.3 `EarlyStopping` \u65e9\u505c\u673a\u5236\\n\\n\u65e9\u505c\u673a\u5236\u7528\u4e8e\u76d1\u63a7\u9a8c\u8bc1\u635f\u5931\uff0c\u5982\u679c\u5728\u8bbe\u5b9a\u7684 `patience` (\u8010\u5fc3) \u8f6e\u6b21\u5185\u9a8c\u8bc1\u635f\u5931\u6ca1\u6709\u6539\u5584\uff0c\u5219\u505c\u6b62\u8bad\u7ec3\uff0c\u5e76\u52a0\u8f7d\u6027\u80fd\u6700\u4f73\u7684\u6a21\u578b\u3002\u8fd9\u53ef\u4ee5\u9632\u6b62\u6a21\u578b\u8fc7\u62df\u5408\u8bad\u7ec3\u6570\u636e\u3002\\n\\n```python\\n# \u65e9\u505c\u673a\u5236\\nclass EarlyStopping:\\n    def __init__(self, patience=100, verbose=True):\\n        self.patience = patience\\n        self.verbose = verbose\\n        self.counter = 0\\n        self.best_score = None\\n        self.early_stop = False\\n        self.val_loss_min = float('''inf''')\\n        self.best_model_state = None\\n      \\n    def __call__(self, val_loss, model):\\n        score = -val_loss # \u901a\u5e38\u7528\u4e8e\u6700\u5927\u5316\u67d0\u4e2a\u6307\u6807\uff0c\u8fd9\u91cc\u662f\u6700\u5c0f\u5316\u635f\u5931\u6240\u4ee5\u53d6\u8d1f\\n      \\n        if self.best_score is None:\\n            self.best_score = score\\n            self.save_checkpoint(val_loss, model)\\n        elif score < self.best_score:\\n            self.counter += 1\\n            if self.verbose:\\n                print(f'''EarlyStopping counter: {self.counter} out of {self.patience}''')\\n            if self.counter >= self.patience:\\n                self.early_stop = True\\n        else:\\n            self.best_score = score\\n            self.save_checkpoint(val_loss, model)\\n            self.counter = 0\\n          \\n    def save_checkpoint(self, val_loss, model):\\n        if self.verbose:\\n            print(f'''\u9a8c\u8bc1\u635f\u5931\u51cf\u5c11 ({self.val_loss_min:.6f} --\x3e {val_loss:.6f}). \u4fdd\u5b58\u6a21\u578b...''')\\n        self.best_model_state = model.state_dict().copy()\\n        self.val_loss_min = val_loss\\n      \\n    def load_best_model(self, model):\\n        model.load_state_dict(self.best_model_state)\\n        return model\\n```\\n\\n### 2.4 \u8bad\u7ec3\u4e0e\u9a8c\u8bc1\u51fd\u6570\\n\\n- `train_epoch`: \u6267\u884c\u4e00\u4e2a\u8bad\u7ec3\u8f6e\u6b21\u3002\u6a21\u578b\u8bbe\u7f6e\u4e3a\u8bad\u7ec3\u6a21\u5f0f (`model.train()`)\uff0c\u8ba1\u7b97L1\u635f\u5931 (`nn.L1Loss()`) \u5e76\u52a0\u4e0aL2\u6b63\u5219\u5316\u635f\u5931\u3002\u4f7f\u7528Adam\u4f18\u5316\u5668\u66f4\u65b0\u6a21\u578b\u53c2\u6570\u3002\\n- `validate_epoch`: \u6267\u884c\u4e00\u4e2a\u9a8c\u8bc1\u8f6e\u6b21\u3002\u6a21\u578b\u8bbe\u7f6e\u4e3a\u8bc4\u4f30\u6a21\u5f0f (`model.eval()`)\uff0c\u8ba1\u7b97\u9a8c\u8bc1\u635f\u5931\uff0c\u5e76\u6536\u96c6\u9884\u6d4b\u7ed3\u679c\u3002\\n\\n```python\\n# \u8bad\u7ec3\u4e00\u4e2aepoch\\ndef train_epoch(model, train_loader, optimizer, scheduler, epoch, progress_callback):\\n    model.train()\\n    total_loss = 0\\n    progress_callback.on_epoch_begin(epoch)\\n  \\n    for i, (inputs, targets) in enumerate(train_loader):\\n        inputs, targets = inputs.to(device), targets.to(device)\\n      \\n        optimizer.zero_grad()\\n        outputs = model(inputs)\\n        loss = nn.L1Loss()(outputs, targets.view(-1, 1))\\n        reg_loss = model.get_l2_loss()\\n        total_loss = loss + reg_loss\\n      \\n        total_loss.backward()\\n        optimizer.step()\\n      \\n        batch_logs = {'''loss''': total_loss.item()}\\n        progress_callback.on_batch_end(i, batch_logs)\\n  \\n    return total_loss.item() / len(train_loader)\\n\\n# \u9a8c\u8bc1\u4e00\u4e2aepoch\\ndef validate_epoch(model, val_loader):\\n    model.eval()\\n    val_loss = 0\\n    predictions = []\\n    targets_list = []\\n  \\n    with torch.no_grad():\\n        for inputs, targets in val_loader:\\n            inputs, targets = inputs.to(device), targets.to(device)\\n            outputs = model(inputs)\\n            val_loss += nn.L1Loss()(outputs, targets.view(-1, 1)).item()\\n          \\n            predictions.extend(outputs.cpu().numpy().flatten())\\n            targets_list.extend(targets.cpu().numpy())\\n  \\n    val_loss /= len(val_loader)\\n    return val_loss, predictions, targets_list\\n```\\n\\n### 2.5 K\u6298\u4ea4\u53c9\u9a8c\u8bc1\\n\\n\u4f7f\u7528\u4e8610\u6298\u4ea4\u53c9\u9a8c\u8bc1 (`KFold`) \u6765\u8bad\u7ec3\u6a21\u578b\u3002\\n\\n- \u5728\u6bcf\u6b21\u6298\u53e0\u4e2d\uff0c\u6570\u636e\u88ab\u5212\u5206\u4e3a\u8bad\u7ec3\u96c6\u548c\u9a8c\u8bc1\u96c6\u3002\\n- \u6a21\u578b\u5728\u8bad\u7ec3\u96c6\u4e0a\u8fdb\u884c\u8bad\u7ec3\uff0c\u5e76\u5728\u9a8c\u8bc1\u96c6\u4e0a\u8bc4\u4f30\u6027\u80fd\uff08\u4f7f\u7528MAE\uff0cMean Absolute Error\uff09\u3002\\n- \u65e9\u505c\u673a\u5236\u548c\u5b66\u4e60\u7387\u8c03\u5ea6\u5668\u5728\u6bcf\u4e2a\u6298\u53e0\u7684\u8bad\u7ec3\u8fc7\u7a0b\u4e2d\u72ec\u7acb\u5e94\u7528\u3002\\n- \u6d4b\u8bd5\u96c6\u7684\u9884\u6d4b\u7ed3\u679c\u662f\u6240\u6709\u6298\u53e0\u9884\u6d4b\u7ed3\u679c\u7684\u5e73\u5747\u503c\uff0c\u8fd9\u6709\u52a9\u4e8e\u63d0\u9ad8\u6a21\u578b\u7684\u6cdb\u5316\u80fd\u529b\u5e76\u51cf\u5c11\u8fc7\u62df\u5408\u3002\\n- MAE\u662f\u8bc4\u4f30\u56de\u5f52\u6a21\u578b\u5e38\u7528\u7684\u6307\u6807\uff0c\u8868\u793a\u9884\u6d4b\u503c\u548c\u771f\u5b9e\u503c\u4e4b\u95f4\u5e73\u5747\u7edd\u5bf9\u8bef\u5dee\u3002\\n\\n```python\\n# K\u6298\u4ea4\u53c9\u9a8c\u8bc1\u8bad\u7ec3\\n# \u8bbe\u7f6e\u4ea4\u53c9\u9a8c\u8bc1\u53c2\u6570\\nn_splits = 10  # KFold\u8981\u6c42\u81f3\u5c11\u4e3a2\\nskf = KFold(n_splits=n_splits, shuffle=True)\\noof = np.zeros(len(X_data)) # Out-of-fold \u9884\u6d4b\\npredictions = np.zeros(len(X_test))  # \u521d\u59cb\u5316\u9884\u6d4b\u7ed3\u679c\u6570\u7ec4\\nmae = 0\\nfold_scores = []\\n\\n# \u8bbe\u7f6e\u8981\u8fd0\u884c\u7684\u6298\u6570\\ntotal_folds = n_splits\\n  \\nprint(f\\\"\u5c06\u8fdb\u884c{total_folds}\u6b21\u8bad\u7ec3\u9a8c\u8bc1...\\\")\\n\\n# \u83b7\u53d6\u6240\u6709\u6298\u7684\u7d22\u5f15\\nall_folds = list(skf.split(X_data, Y_data))\\n# \u53ea\u6267\u884c\u6307\u5b9a\u6b21\u6570\u7684\u5faa\u73af\\nfor i in range(total_folds):\\n    # ... (\u8bad\u7ec3\u548c\u9a8c\u8bc1\u5faa\u73af\uff0c\u65e9\u505c\uff0c\u9884\u6d4b\u6d4b\u8bd5\u96c6\u548c\u9a8c\u8bc1\u96c6) ...\\n  \\n    # \u9884\u6d4b\u6d4b\u8bd5\u96c6\\n    model.eval()\\n    test_tensor = torch.FloatTensor(X_test).to(device)\\n    test_dataset = TensorDataset(test_tensor, torch.zeros(len(X_test)))\\n    test_loader = DataLoader(test_dataset, batch_size=batch_size_cv)\\n  \\n    test_preds = []\\n    with torch.no_grad():\\n        for inputs, _ in test_loader:\\n            inputs = inputs.to(device)\\n            outputs = model(inputs)\\n            test_preds.extend(outputs.cpu().numpy().flatten())\\n  \\n    predictions += np.array(test_preds) / skf.n_splits # \u5bf9\u6240\u6709\u6298\u7684\u9884\u6d4b\u8fdb\u884c\u5e73\u5747\\n  \\n    # \u9884\u6d4b\u9a8c\u8bc1\u96c6 (\u7528\u4e8e\u8ba1\u7b97oof\u548c\u5f53\u524d\u6298\u7684MAE)\\n    val_preds_final = []\\n    with torch.no_grad():\\n        for inputs, _ in DataLoader(TensorDataset(val_x_tensor, torch.zeros(len(val_x))), batch_size=batch_size_cv):\\n            inputs = inputs.to(device)\\n            outputs = model(inputs)\\n            val_preds_final.extend(outputs.cpu().numpy().flatten())\\n  \\n    oof[val_idx] = np.array(val_preds_final)\\n    fold_mae = mean_absolute_error(val_y, oof[val_idx])\\n    fold_scores.append(fold_mae)\\n    mae += fold_mae / skf.n_splits\\n    fold_time = time.time() - fold_start_time\\n    print(f\\\"\u7b2c {i+1} \u6298 MAE: {fold_mae:.4f}\\\")\\n    print(f\\\"\u7b2c {i+1} \u6298\u8017\u65f6: {fold_time:.2f}\u79d2\\\")\\n\\nprint(f\\\"\\\\n\u4ea4\u53c9\u9a8c\u8bc1\u5b8c\u6210! \u5404\u6298MAE: {[f'{score:.4f}' for score in fold_scores]}\\\")\\nprint(f\\\"\u5e73\u5747 MAE: {mae:.4f}\\\")\\n```\\n\\n### 2.6 \u7ed3\u679c\u4fdd\u5b58\\n\\n\u6700\u540e\uff0c\u4ee3\u7801\u5c06\u8bad\u7ec3\u96c6\u4e0a\u7684oof\u9884\u6d4b\u548c\u6d4b\u8bd5\u96c6\u4e0a\u7684\u5e73\u5747\u9884\u6d4b\u7ed3\u679c\u4fdd\u5b58\u4e3aCSV\u6587\u4ef6\uff0c\u4ee5\u4fbf\u540e\u7eed\u53ef\u80fd\u8fdb\u884c\u6a21\u578b\u878d\u5408\u3002\u540c\u65f6\uff0c\u4e5f\u4fdd\u5b58\u4e86\u6700\u7ec8\u7684\u6d4b\u8bd5\u96c6\u9884\u6d4b\u7ed3\u679c\u6587\u4ef6\u3002\\n\\n```python\\n# \u751f\u6210\u63d0\u4ea4\u6587\u4ef6\\n# \u4fdd\u5b58\u7528\u4e8e\u6a21\u578b\u878d\u5408\u7684\u8bad\u7ec3\u96c6\u548c\u6d4b\u8bd5\u96c6\u9884\u6d4b\u7ed3\u679c\\ntrain_results = pd.DataFrame()\\ntrain_results['''SaleID'''] = Train_SaleID\\ntrain_results['''price'''] = oof  # \u795e\u7ecf\u7f51\u7edc\u76f4\u63a5\u5728\u539f\u59cb\u7a7a\u95f4\u8bad\u7ec3\uff0c\u65e0\u9700\u8f6c\u6362\\ntrain_results.to_csv(user_data_path + '''nn_train.csv''', index=False)\\n\\ntest_results = pd.DataFrame()\\ntest_results['''SaleID'''] = Test_SaleID\\ntest_results['''price'''] = predictions  # \u795e\u7ecf\u7f51\u7edc\u76f4\u63a5\u5728\u539f\u59cb\u7a7a\u95f4\u9884\u6d4b\uff0c\u65e0\u9700\u8f6c\u6362\\ntest_results.to_csv(user_data_path + '''nn_test.csv''', index=False)\\n\\n# \u4fdd\u5b58\u6700\u7ec8\u9884\u6d4b\u7ed3\u679c\\nsub = pd.DataFrame()\\nsub['''SaleID'''] = Test_SaleID\\nsub['''price'''] = predictions\\nsub.to_csv(output_path + '''predictions_nn.csv''', index=False)\\nprint(f\\\"\u9884\u6d4b\u7ed3\u679c\u5df2\u4fdd\u5b58\u5230: {output_path}predictions_nn.csv\\\")\\nprint(f\\\"\u6a21\u578b\u878d\u5408\u6240\u9700\u6587\u4ef6\u5df2\u4fdd\u5b58\u5230: {user_data_path}\\\")\\n```\\n\\n---\\n\\n## \u7ed3\u8bed\\n\\n\u5c3d\u7ba1\u6211\u4ed8\u51fa\u4e86\u5927\u91cf\u52aa\u529b\uff0c\u4f46\u6700\u7ec8\u672a\u80fd\u767b\u9876\u3002\u7b2c\u4e00\u540d\u7684\u5206\u6570\u9ad8\u8fbe391\uff0c\u6211\u731c\u6d4b\u4ed6\u53ef\u80fd\u8fdb\u884c\u4e86\u975e\u5e38\u7279\u522b\u7684\u7279\u5f81\u5de5\u7a0b\u3002\u6211\u8fd8\u662f\u633a\u671f\u5f85\u7740\u7b2c\u4e00\u540d\u7684\u5fc3\u5f97\u5206\u4eab\uff0c\u5e0c\u671b\u80fd\u4ece\u4e2d\u5b66\u4e60\u5230\u66f4\u591a\u7279\u5f81\u7684\u5904\u7406\u65b9\u5f0f\u3002\u4e5f\u6b22\u8fce\u5927\u5bb6\u5411\u6211\u63d0\u95ee\uff0c\u4e00\u8d77\u5b66\u4e60\uff0c\u4e00\u8d77\u8fdb\u6b65\"}]}}")}}]);